@strawberry.type
class Review:
    id: strawberry.ID
    author: str
    rating: int
    title: t.Optional[str]
    body: t.Optional[str]
    created_at: datetime


@strawberry.type
class Seller:
    id: strawberry.ID
    name: str
    website: t.Optional[str]
    created_at: datetime


@strawberry.type
class Category:
    id: strawberry.ID
    name: str
    slug: str
