@strawberry.type
class Image:
    id: strawberry.ID
    url: str
    alt_text: t.Optional[str]
    sort_order: int
    created_at: datetime


@strawberry.type
class Product:
    id: strawberry.ID
    sku: str
    name: str
    description: t.Optional[str]
    price: float
    currency: str
    created_at: datetime
    updated_at: datetime

    @strawberry.field
    def reviews(self, info: Info) -> t.List[Review]:
        p: ProductModel = info.context["product_model"]
        return [
            Review(
                id=str(r.id),
                author=r.author,
                rating=r.rating,
                title=r.title,
                body=r.body,
                created_at=r.created_at,
            )
            for r in p.reviews
        ]

    @strawberry.field
    def images(self, info: Info) -> t.List[Image]:
        p: ProductModel = info.context["product_model"]
        imgs = sorted(p.images, key=lambda i: (i.sort_order, i.id))
        return [
            Image(
                id=str(i.id),
                url=i.url,
                alt_text=i.alt_text,
                sort_order=i.sort_order,
                created_at=i.created_at,
            )
            for i in imgs
        ]

    @strawberry.field
    def categories(self, info: Info) -> t.List[Category]:
        p: ProductModel = info.context["product_model"]
        return [
            Category(
                id=str(c.id),
                name=c.name,
                slug=c.slug,
                created_at=c.created_at,
            )
            for c in p.categories
        ]

    @strawberry.field
    def sellers(self, info: Info) -> t.List[Seller]:
        p: ProductModel = info.context["product_model"]
        return [
            Seller(
                id=str(s.id),
                name=s.name,
                website=s.website,
                created_at=s.created_at,
            )
            for s in p.sellers
        ]


def product_from_model(model: ProductModel) -> Product:
    p = Product(
        id=str(model.id),
        sku=model.sku,
        name=model.name,
        description=model.description,
        price=float(model.price),
        currency=model.currency,
        created_at=model.created_at,
        updated_at=model.updated_at,
    )
    return p


def with_product_model_context(info: Info, model: ProductModel):
    info.context["product_model"] = model
    return info


def get_db(info: Info):
    return info.context["db"]


@strawberry.input
class ProductFilterInput:
    q: t.Optional[str] = None
    sku: t.Optional[str] = None
    min_price: t.Optional[float] = None
    max_price: t.Optional[float] = None
    category_slug: t.Optional[str] = None
    seller_id: t.Optional[strawberry.ID] = None


@strawberry.type
class Query:
    @strawberry.field
    def product(self, info: Info, id: strawberry.ID) -> t.Optional[Product]:
        db = get_db(info)
        model = (
            db.query(ProductModel)
            .options(
                selectinload(ProductModel.reviews),
                selectinload(ProductModel.images),
                selectinload(ProductModel.categories),
                selectinload(ProductModel.sellers),
            )
            .filter(ProductModel.id == int(id))
            .first()
        )
        if not model:
            return None
        info.context["product_model"] = model
        return product_from_model(model)

    @strawberry.field
    def product_by_sku(self, info: Info, sku: str) -> t.Optional[Product]:
        db = get_db(info)
        model = (
            db.query(ProductModel)
            .options(
                selectinload(ProductModel.reviews),
                selectinload(ProductModel.images),
                selectinload(ProductModel.categories),
                selectinload(ProductModel.sellers),
            )
            .filter(ProductModel.sku == sku)
            .first()
        )
        if not model:
            return None
        info.context["product_model"] = model
        return product_from_model(model)

    @strawberry.field
    def products(
        self,
        info: Info,
        filter: t.Optional[ProductFilterInput] = None,
        offset: int = 0,
        limit: int = 50,
    ) -> t.List[Product]:
        db = get_db(info)
        q = db.query(ProductModel)

        if filter:
            if filter.q:
                like = f"%{filter.q}%"
                q = q.filter((ProductModel.name.ilike(like)) | (ProductModel.description.ilike(like)))
            if filter.sku:
                q = q.filter(ProductModel.sku == filter.sku)
            if filter.min_price is not None:
                q = q.filter(ProductModel.price >= filter.min_price)
            if filter.max_price is not None:
                q = q.filter(ProductModel.price <= filter.max_price)
            if filter.category_slug:
                q = q.join(ProductModel.categories).filter(CategoryModel.slug == filter.category_slug)
            if filter.seller_id:
                q = q.join(ProductModel.sellers).filter(SellerModel.id == int(filter.seller_id))

        q = q.order_by(ProductModel.id.asc())

        q = q.options(
            selectinload(ProductModel.reviews),
            selectinload(ProductModel.images),
            selectinload(ProductModel.categories),
            selectinload(ProductModel.sellers),
        )

        models = q.offset(offset).limit(limit).all()

        products: t.List[Product] = []
        for m in models:
            info.context["product_model"] = m
            products.append(product_from_model(m))
        return products

    @strawberry.field
    def categories(self, info: Info) -> t.List[Category]:
        db = get_db(info)
        cats = db.query(CategoryModel).order_by(CategoryModel.name.asc()).all()
        return [
            Category(id=str(c.id), name=c.name, slug=c.slug, created_at=c.created_at)
            for c in cats
        ]

    @strawberry.field
    def sellers(self, info: Info) -> t.List[Seller]:
        db = get_db(info)
        sellers = db.query(SellerModel).order_by(SellerModel.name.asc()).all()
        return [
            Seller(id=str(s.id), name=s.name, website=s.website, created_at=s.created_at)
            for s in sellers
        ]


class SQLAlchemySessionExtension(Extension):
    def on_request_start(self):
        self.execution_context.context["db"] = SessionLocal()

    def on_request_end(self):
        db = self.execution_context.context.get("db")
        if db is not None:
            try:
                db.close()
            finally:
                self.execution_context.context.pop("db", None)


schema = strawberry.Schema(
    query=Query,
    config=StrawberryConfig(auto_camel_case=False),
    extensions=[SQLAlchemySessionExtension],
)

init_db()
if os.getenv("SEED_DB", "1").lower() in {"1", "true", "yes", "y"}:
    seed_db()

app = GraphQL(schema, graphiql=True)